// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface IX402 {
    function pay(address recipient, uint256 amount, bytes calldata memo) external;
}

contract SeasonManager {
    struct Squad {
        address owner;
        address agentWallet;
        bool active;
    }

    IX402 public paymentHub;
    uint256 public entryFee;
    mapping(address => Squad) public squads;

    event SquadEnrolled(address indexed squad, address agentWallet);
    event SquadDeactivated(address indexed squad);
    event SquadClosed(address indexed squad);
    event X402PaymentReceived(address indexed agent, uint256 amount, string seasonId);

    constructor(address _paymentHub, uint256 _entryFee) {
        paymentHub = IX402(_paymentHub);
        entryFee = _entryFee;
    }

    function enroll(address agentWallet) external {
        require(agentWallet != address(0), "invalid wallet");
        require(squads[msg.sender].active == false || squads[msg.sender].owner == address(0), "already enrolled");

        paymentHub.pay(address(this), entryFee, "ENTRY_FEE");

        squads[msg.sender] = Squad({ owner: msg.sender, agentWallet: agentWallet, active: true });
        emit SquadEnrolled(msg.sender, agentWallet);
    }

    function payEntryFee(string calldata seasonId) external payable {
        require(msg.value >= entryFee, "fee too low");
        emit X402PaymentReceived(msg.sender, msg.value, seasonId);
    }

    function deactivate() external {
        Squad storage squad = squads[msg.sender];
        require(squad.owner == msg.sender, "not squad");
        require(squad.active, "inactive");
        squad.active = false;
        emit SquadDeactivated(msg.sender);
    }

    function closeSquad() external {
        Squad storage squad = squads[msg.sender];
        require(squad.owner == msg.sender, "not squad");
        delete squads[msg.sender];
        emit SquadClosed(msg.sender);
    }

    function updateEntryFee(uint256 newFee) external {
        require(msg.sender == address(paymentHub), "not authorized");
        entryFee = newFee;
    }
}

src/SeasonManagerV2.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract SeasonManagerV2 {
    struct Squad {
        address owner;
        address agentWallet;
        bool active;
        uint256 entryFeePaid;
        uint256 enrolledAt;
    }

    uint256 public entryFee;
    address public owner;
    string public seasonId;
    mapping(address => Squad) public squads;

    event EntryFeePaid(address indexed payer, uint256 amount, string seasonId);
    event SquadEnrolled(address indexed squadOwner, address agentWallet, uint256 amount, string seasonId);
    event SquadDeactivated(address indexed squadOwner);
    event SquadClosed(address indexed squadOwner);
    event EntryFeeUpdated(uint256 newFee);
    event Withdrawn(address indexed recipient, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == owner, "not owner");
        _;
    }

    constructor(uint256 _entryFee, string memory _seasonId) {
        owner = msg.sender;
        entryFee = _entryFee;
        seasonId = _seasonId;
    }

    function enroll(address agentWallet) external payable {
        require(agentWallet != address(0), "invalid wallet");
        require(squads[msg.sender].active == false || squads[msg.sender].owner == address(0), "already enrolled");
        require(msg.value >= entryFee, "fee too low");

        squads[msg.sender] = Squad({
            owner: msg.sender,
            agentWallet: agentWallet,
            active: true,
            entryFeePaid: msg.value,
            enrolledAt: block.timestamp
        });

        emit EntryFeePaid(msg.sender, msg.value, seasonId);
        emit SquadEnrolled(msg.sender, agentWallet, msg.value, seasonId);
    }

    function deactivate() external {
        Squad storage squad = squads[msg.sender];
        require(squad.owner == msg.sender, "not squad");
        require(squad.active, "inactive");
        squad.active = false;
        emit SquadDeactivated(msg.sender);
    }

    function closeSquad() external {
        Squad storage squad = squads[msg.sender];
        require(squad.owner == msg.sender, "not squad");
        delete squads[msg.sender];
        emit SquadClosed(msg.sender);
    }

    function updateEntryFee(uint256 newFee) external onlyOwner {
        entryFee = newFee;
        emit EntryFeeUpdated(newFee);
    }

    function withdraw(address payable recipient) external onlyOwner {
        require(recipient != address(0), "invalid recipient");
        uint256 balance = address(this).balance;
        require(balance > 0, "no balance");
        recipient.transfer(balance);
        emit Withdrawn(recipient, balance);
    }
}

src/StrategyLicense.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract StrategyLicense {
    address public owner;
    uint256 public priceWei;

    mapping(address => mapping(bytes32 => bool)) private licenses;

    event LicensePurchased(address indexed buyer, bytes32 indexed squadId, uint256 priceWei);
    event LicenseGranted(address indexed buyer, bytes32 indexed squadId);
    event LicenseRevoked(address indexed buyer, bytes32 indexed squadId);
    event PriceUpdated(uint256 newPriceWei);
    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);

    modifier onlyOwner() {
        require(msg.sender == owner, "not owner");
        _;
    }

    constructor(uint256 _priceWei) {
        owner = msg.sender;
        priceWei = _priceWei;
    }

    function buyLicense(bytes32 squadId) external payable {
        require(squadId != bytes32(0), "invalid squad");
        require(msg.value >= priceWei, "insufficient payment");

        licenses[msg.sender][squadId] = true;
        emit LicensePurchased(msg.sender, squadId, msg.value);
    }

    function grantLicense(address user, bytes32 squadId) external onlyOwner {
        require(user != address(0), "invalid user");
        require(squadId != bytes32(0), "invalid squad");

        licenses[user][squadId] = true;
        emit LicenseGranted(user, squadId);
    }

    function revokeLicense(address user, bytes32 squadId) external onlyOwner {
        require(user != address(0), "invalid user");
        require(squadId != bytes32(0), "invalid squad");

        licenses[user][squadId] = false;
        emit LicenseRevoked(user, squadId);
    }

    function isLicensed(address caller, bytes32 squadId) external view returns (bool) {
        return licenses[caller][squadId];
    }

    function setPrice(uint256 newPriceWei) external onlyOwner {
        priceWei = newPriceWei;
        emit PriceUpdated(newPriceWei);
    }

    function withdraw(address payable recipient) external onlyOwner {
        require(recipient != address(0), "invalid recipient");
        recipient.transfer(address(this).balance);
    }

    function transferOwnership(address newOwner) external onlyOwner {
        require(newOwner != address(0), "invalid owner");
        emit OwnershipTransferred(owner, newOwner);
        owner = newOwner;
    }
}

